export const getAnnouncements = (lang: 'tr' | 'en' | 'es') => {
  return announcementsData.map(a => ({
    id: a.id,
    image: a.image,
    date: a.translations[lang]?.date || a.translations['en'].date,
    title: a.translations[lang]?.title || a.translations['en'].title,
    category: a.translations[lang]?.category || a.translations['en'].category,
    excerpt: a.translations[lang]?.excerpt || a.translations['en'].excerpt,
    content: a.translations[lang]?.content || a.translations['en'].content
  }));
};

export const announcements = announcementsData.map(a => ({
  id: a.id,
  image: a.image,
  date: a.translations['tr'].date,
  title: a.translations['tr'].title,
  category: a.translations['tr'].category,
  excerpt: a.translations['tr'].excerpt,
  content: a.translations['tr'].content
}));
